  "exercises": [
    {
      "words": ["Je", "ai", "dix", "ans."],
      "translation": "Ich habe zehn Jahre.",
      "explanation": "Bei A1-Sätzen folgt die Standardreihenfolge: Subjekt (Je), Verb (ai), Objekt (dix ans). Das Jahr wird mit 'ans' ausgedrückt."
    },
    {
      "words": ["Il", "est", "neuf."],
      "translation": "Er ist neun.",
      "explanation": "Im A1-Niveau steht das Subjekt (Il), dann das Verb (est) und danach der Adjektiv- oder Zahlwortteil (neuf)."
    },
    {
      "words": ["Nous", "avons", "deux", "chats."],
      "translation": "Wir haben zwei Katzen.",
      "explanation": "Das Subjekt (Nous) kommt zuerst, dann das Verb (avons), gefolgt von der Zahl und dem Nomen (deux chats)."
    },
    {
      "words": ["Tu", "es", "à", "dix."],
      "translation": "Du bist um zehn.",
      "explanation": "Das Subjekt (Tu) steht vor dem Verb (es), gefolgt von der Zeitangabe (à dix). Bei Uhrzeiten wird 'à' verwendet."
    },
    {
      "words": ["Elle", "a", "un", "chien."],
      "translation": "Sie hat einen Hund.",
      "explanation": "Subjekt (Elle), Verb (a), Artikel (un) und Nomen (chien). Bei A1 verwendet man einfachen Satzbau mit SVO-Struktur."
    }
  ]
}
